/// Reproduce `array_in` for an identifier-only `text[]` literal like
/// `"{adrelid, adnum}"`: strip the surrounding braces, split on commas, trim
/// ASCII whitespace around each element, and collect the raw bytes. These
/// literals contain only catalog column identifiers (no quoting, NULLs or
/// nested arrays), so this faithfully matches what `array_in` would produce for
/// the seam's purposes.
fn array_in_identifiers(literal: &str) -> Vec<Vec<u8>> {
    let bytes = literal.as_bytes();
    // Strip leading '{' and trailing '}'.
    let inner = bytes
        .strip_prefix(b"{")
        .and_then(|b| b.strip_suffix(b"}"))
        .expect("sys_fk_relationships literal must be brace-wrapped");
    inner
        .split(|&c| c == b',')
        .map(|elem| {
            let start = elem.iter().position(|c| !c.is_ascii_whitespace()).unwrap_or(elem.len());
            let end = elem
                .iter()
                .rposition(|c| !c.is_ascii_whitespace())
                .map(|i| i + 1)
                .unwrap_or(start);
            elem[start..end].to_vec()
        })
        .collect()
}

/// Build the full `pg_get_catalog_foreign_keys()` row set from
/// [`SYS_FK_RELATIONSHIPS`] (misc.c:495). One [`CatalogForeignKeyRow`] per
/// entry, with the `fk_columns`/`pk_columns` literals passed through
/// [`array_in_identifiers`] (the `array_in` of misc.c:539/544).
pub fn build_sys_fk_rows() -> Vec<CatalogForeignKeyRow> {
    SYS_FK_RELATIONSHIPS
        .iter()
        .map(|&(fktable, fkcols, pktable, pkcols, is_array, is_opt)| CatalogForeignKeyRow {
            fktable,
            fkcols: array_in_identifiers(fkcols),
            pktable,
            pkcols: array_in_identifiers(pkcols),
            is_array,
            is_opt,
        })
        .collect()
}
